// Uazapi tem múltiplos formatos de payload. Normaliza aqui.
// Formatos suportados:
//  A) { event, message: { fromMe, sender, chatid, text, type, messageid, senderName }, token }
//  B) { event, messages: [{ key:{fromMe,remoteJid,id}, message:{conversation|extendedTextMessage:{text}} }], owner }
//  C) { event, data: { ... (A ou B) ... }, token }
const raw = $input.first().json.body ?? $input.first().json;
const root = raw.data && typeof raw.data === 'object' ? raw.data : raw;
const instanceToken = root.token || root.owner || raw.token || raw.owner || '';

function cleanPhone(jid) {
  if (!jid) return '';
  return String(jid).split('@')[0].replace(/\D/g, '');
}

function pushText(out, m) {
  // formato A
  if (m && typeof m === 'object' && ('fromMe' in m || 'sender' in m || 'chatid' in m || 'text' in m)) {
    out.push({
      fromMe: m.fromMe === true,
      phone: cleanPhone(m.sender || m.chatid || m.from),
      senderName: m.senderName || m.pushname || '',
      text: String(m.text ?? m.body ?? m.caption ?? '').trim(),
      type: String(m.type || m.messageType || 'text').toLowerCase(),
      messageId: String(m.messageid || m.id || m.key?.id || ''),
      timestamp: m.timestamp || m.messageTimestamp || Date.now()
    });
    return;
  }
  // formato B (baileys-like)
  if (m && m.key) {
    const msg = m.message || {};
    const text = msg.conversation || msg.extendedTextMessage?.text || msg.imageMessage?.caption || msg.videoMessage?.caption || msg.buttonsResponseMessage?.selectedButtonId || msg.listResponseMessage?.singleSelectReply?.selectedRowId || '';
    const msgType = Object.keys(msg)[0] || 'text';
    out.push({
      fromMe: m.key.fromMe === true,
      phone: cleanPhone(m.key.remoteJid),
      senderName: m.pushName || '',
      text: String(text).trim(),
      type: msgType.replace('Message', '').toLowerCase() || 'text',
      messageId: String(m.key.id || ''),
      timestamp: m.messageTimestamp || Date.now()
    });
  }
}

const out = [];
if (root.message) pushText(out, root.message);
if (Array.isArray(root.messages)) for (const m of root.messages) pushText(out, m);
if (!out.length && raw.message) pushText(out, raw.message);

const withToken = out.map(o => ({ json: { ...o, instanceToken } }));
return withToken.length ? withToken : [{ json: { _skip: true, instanceToken } }];

