// Verifica se o texto bate alguma keyword ativa. Primeiro match vence.
const campaigns = $input.all().map(i => i.json).filter(c => c.keyword);
const text = ($('Extract payload').first().json.text || '').toLowerCase().trim();
let matched = null;
for (const c of campaigns) {
  const kw = String(c.keyword).toLowerCase().trim();
  if (!kw) continue;
  const mode = c.match_mode || 'contains';
  const hit = mode === 'exact' ? text === kw : text.includes(kw);
  if (hit) { matched = c; break; }
}
return [{
  json: {
    ...$('Extract payload').first().json,
    conversationId: $('Pg — Upsert conversation').first().json.id,
    matchedCampaign: matched,
    hasMatch: !!matched
  }
}];

