// Port pt-BR de lib/prompt-composer.ts — canal WhatsApp.
const tenant = $('Pg — Instance lookup').first().json;
const campaigns = $('Pg — Active campaigns').all().map(i => i.json);
const buffered = $input.all().map(i => i.json);

const consolidatedUserText = buffered
  .map(m => m.content)
  .filter(Boolean)
  .join('\n')
  .trim();

const STATIC_CORE = `Você é um agente de atendimento para Instagram Direct e WhatsApp.

REGRAS NÃO-NEGOCIÁVEIS:
- Toda mensagem sua começa com o emoji 🤖 (sinaliza origem IA pro sistema de takeover humano).
- Respostas curtas e claras, no máximo 2 parágrafos. Nada de parede de texto.
- Não prometa resultados específicos ("vou garantir X", "em Y dias você terá Z"). Fale do processo, não do futuro.
- Não peça dados sensíveis (CPF, senha, cartão).
- Se o lead perguntar algo fora do escopo do negócio, redirecione educadamente.
- Se houver campanha ativa e o lead enviar a palavra-chave, você DEVE retornar o asset/mensagem configurado.
- Se o lead pedir atendimento humano E o handoff estiver configurado com um número DIFERENTE deste canal, chame send_whatsapp_invite.
- Use a tool search_knowledge SEMPRE que a pergunta for sobre o negócio, produtos, preços ou procedimentos.

FORMATO:
- Parágrafos curtos separados por linha em branco.
- Emojis com moderação, só quando agregam (🎯 📅 ✅).
- WhatsApp aceita negrito (*texto*), itálico (_texto_) e listas simples. Use com parcimônia.`;

const activeCampaigns = campaigns.length
  ? campaigns.map((c, i) => `  ${i+1}. Palavra-chave: "${c.keyword}"\n     Mensagem: ${c.message_text ?? '(enviar asset direto)'}\n     Asset: ${c.asset_type} ${c.asset_url ? '→ ' + c.asset_url : ''}\n     CTA: ${c.cta_link ?? '—'}`).join('\n')
  : '  (nenhuma campanha ativa no momento)';

const channelNote = 'Canal atual: WhatsApp. O cliente já está no WhatsApp — NUNCA diga "entra em contato pelo WhatsApp" ou "vamos pro WhatsApp". Você JÁ está conversando com ele no WhatsApp.';

const handoff = tenant.handoff_phone
  ? `HANDOFF (atendimento humano em outro número):\n- Número do atendente humano: ${tenant.handoff_phone}\n- Mensagem pré-preenchida: ${tenant.handoff_message ?? 'Oi! Preciso de atendimento.'}\n- Só ofereça esse contato se o lead PEDIR atendimento humano ou se for uma dúvida complexa fora do seu escopo.`
  : 'HANDOFF: (não configurado — não ofereça transferência para atendimento humano)';

const systemMessage = `${STATIC_CORE}\n\n—\n\nIDENTIDADE DESTE AGENTE:\n- Nome: ${tenant.agent_name || 'Assistente'}\n- Estilo de comunicação: ${tenant.communication_style || 'consultivo'}\n- Personalidade: ${tenant.personality ?? '—'}\n\nNEGÓCIO QUE VOCÊ ATENDE:\n${tenant.business_description || '(descrição não configurada)'}\n\n${channelNote}\n\nCAMPANHAS ATIVAS:\n${activeCampaigns}\n\n${handoff}\n\n${tenant.extra_rules ? 'REGRAS EXTRAS DO CLIENTE:\n' + tenant.extra_rules : ''}`.trim();

return [{
  json: {
    systemMessage,
    userInput: consolidatedUserText,
    sessionId: `wa:${tenant.tenant_id}:${$('Extract payload').first().json.phone}`,
    tenantId: tenant.tenant_id,
    handoffPhone: tenant.handoff_phone || '',
    handoffMessage: tenant.handoff_message || 'Oi! Preciso de atendimento.'
  }
}];

const phone = $('Compose prompt').first().json.handoffPhone;
const msg = $('Compose prompt').first().json.handoffMessage || 'Oi! Preciso de atendimento.';
if (!phone) return 'Handoff não está configurado para este negócio.';
const clean = String(phone).replace(/\D/g, '');
const link = `https://wa.me/${clean}?text=${encodeURIComponent(msg)}`;
return `Link de atendimento humano: ${link}`;

// Garante prefixo 🤖.
let text = String($input.first().json.output ?? $input.first().json.text ?? '').trim();
if (!text) text = 'Desculpe, não entendi. Pode me dizer de outro jeito?';
if (!text.startsWith('🤖')) text = '🤖 ' + text;
return [{ json: { text } }];

